var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"PRIEST_NPC_HARMONY_NULL","text":{"KOREA":"태양이 사라지고. 또다시 마물이 들끓기 시작했으니.","JPN":"太陽が消え、再び魔物が暴れ出した。","ENG":"The sun has disappeared, and monsters have started to take over again.","TWN":"太陽消失了，怪物又開始肆虐。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRIEST_NPC_HARMONY_NULL","text":{"KOREA":"이는 불경한 어둠 타기리온이 또다시 하늘아래 재림하였음이라.","JPN":"これは不敬な闇、タギリオンが再びこの空の下に再臨したことである。","ENG":"The unholy darkness, Thagirion, has once again been reincarnated.","TWN":"這表示不祥的黑暗塔基里翁再次降臨。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRIEST_NPC_HARMONY_NULL","text":{"KOREA":"그리하여 우리는 연주와 기도를 통해 태양문의 빛을 높이 밝히니…!","JPN":"そして我らは演奏と祈りによって太陽の扉の光を高く照らす……！","ENG":"So let our prayers and performances illuminate the Solar Gates...!","TWN":"於是我們透過演奏與祈禱使太陽門之光再次照耀……！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRIEST_NPC_HARMONY_NULL","text":{"KOREA":"다시 한번 위대한 정적께서 타기리온을 멸하여 우리를 구원으로 이끄실 것이다!","JPN":"今一度偉大なる静寂によりタギリオンを滅ぼし、我らを救いへと導くであろう！","ENG":"For the Great Silence will defeat Thagirion and bring salvation once again!","TWN":"偉大的寂靜將再次消滅塔基里翁，帶領我們走向救贖！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"아우드라는… 끝내 출정식에 모습을 드러내지 않았군.","JPN":"アウドラは……最後まで出征式に姿を見せなかったのだな。","ENG":"Audra... did not show up at the ceremony of war after all.","TWN":"奧德拉……終究還是沒有在遠征儀式露面。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"실로 안타깝군요.","JPN":"実に残念です。","ENG":"What a shame, indeed.","TWN":"太可惜了。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"예하께서 마지막 아량을 베푸셨음에도, 그 기대를 배반하다니","JPN":"猊下が最後まで寛容に対応してくださったのに、その期待を裏切るとは。","ENG":"You showed your generosity, and yet she has betrayed your expectations.","TWN":"主教已經給予了最後的寬容，她卻還是背叛了這份心意。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그토록 믿으시던 아이가 제 악단의 귀를 도려내고 도망칠 줄 누가 알았을까요?","JPN":"あんなに信じていた子どもが私の楽団の耳を切り、逃げ出すとは思いもしませんでした。","ENG":"Who would have thought that the child you trusted so much would run away after tearing my orchestra's ears?","TWN":"誰會料到如此信任的孩子會割下樂團的耳朵逃跑？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"정녕 그 아이가… 자신의 누이를 찾기 위해 그런 만행을 저지른 것인가?","JPN":"あの子が……自分の姉を探すためにそのようなことをしたとは誠か？","ENG":"Did the child... commit such brutality all to just find her sister?","TWN":"那孩子……真的是為了尋找自己的姊姊做出了那種事？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"이교도를 신뢰하는 것엔 대가가 필요한 법이죠. 지금이라도 교훈을 얻으셨다면 다행입니다.","JPN":"異教徒を信じるには対価が必要なものです。今からでも教訓を得たのであれば幸いでございます。","ENG":"Trusting a pagan always comes with a price. I would be glad if this helped you learn your lesson.","TWN":"這就是信任一個異教徒的代價，希望能從中吸取教訓。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그 아이가 도망친 곳이 겨울의 땅이었다면, 분명 이번에도 타기리온과 마주치기 전에 만날 수 있겠지.","JPN":"逃げたのが冬の地であれば、きっと今回もタギリオンと出くわす前に会えるであろう。","ENG":"If she ran to the Gelid Lands, I shall be able to come across her again before encountering Thagirion.","TWN":"如果那孩子逃到了冬境，應該能在她遇到塔基里翁之前找到她。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"아직도… 그 아이에 대한 미련을 버리지 못하시는 건가요?","JPN":"まだ……あの子どもに未練がおありですか？","ENG":"Have you... still not let go of your attachment to that child?","TWN":"主教還是……忘不了她？……還是沒有放棄她嗎？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"내가 직접 그 아이를 만나 묻겠다.","JPN":"我が直に会って話を聞こう。","ENG":"I will meet her and ask her myself.","TWN":"我要親自去找她問。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"사정이 있다면 경청할 것이고, 악의가 있었다면 교화를 통해서라도…","JPN":"事情があるなら耳を傾けてやろう。悪意があったのなら教化をしてでも……","ENG":"I will listen if she had a good reason, and if there was any malice...","TWN":"如果有理由，我會聆聽。如果有惡意，我會教化……"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그 아이를 구원할 것이다.","JPN":"あの子どもを救う。","ENG":"I will save her through edification.","TWN":"拯救那個孩子。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"…그렇군요.","JPN":"……そうですか。","ENG":"...I see.","TWN":"……這樣啊。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그러니, 그전까지 엘리시온의 주민들에겐 그녀가 저지른 일은 비밀로 부탁하마.","JPN":"だから、それまではエリシオンの民にはあの子がしたことは内密に頼む。","ENG":"So until then, I ask you to keep what she did a secret from the residents of Elysion.","TWN":"所以在那之前，那孩子做的事要對艾利森的居民們保密。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};